import{_ as e,o as a,c as l,a7 as i}from"./chunks/framework.C5fSpjcB.js";const f=JSON.parse('{"title":"育成ガイド","description":"","frontmatter":{},"headers":[],"relativePath":"ja/awakeners/leveling.md","filePath":"ja/awakeners/leveling.md","lastUpdated":1775394001000}'),r={name:"ja/awakeners/leveling.md"};function n(d,t,h,s,o,c){return a(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="育成ガイド" tabindex="-1">育成ガイド <a class="header-anchor" href="#育成ガイド" aria-label="Permalink to &quot;育成ガイド&quot;">​</a></h1><p>覚醒体の育成方法を解説します。効率よくキャラクターを強化し、戦力を高めましょう。</p><h2 id="育成要素一覧" tabindex="-1">育成要素一覧 <a class="header-anchor" href="#育成要素一覧" aria-label="Permalink to &quot;育成要素一覧&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">育成要素</th><th style="text-align:left;">効果</th><th style="text-align:center;">上限</th></tr></thead><tbody><tr><td style="text-align:left;">レベルアップ</td><td style="text-align:left;">基礎ステータス上昇</td><td style="text-align:center;">プレイヤーLv依存</td></tr><tr><td style="text-align:left;">昇格（突破）</td><td style="text-align:left;">レベル上限解放・スキル解放</td><td style="text-align:center;">複数段階</td></tr><tr><td style="text-align:left;">スキル強化</td><td style="text-align:left;">カード性能向上</td><td style="text-align:center;">Lv.6</td></tr><tr><td style="text-align:left;">啓霊</td><td style="text-align:left;">固有パッシブ解放</td><td style="text-align:center;">最大凸</td></tr><tr><td style="text-align:left;">運命の輪</td><td style="text-align:left;">専用装備でステータス強化</td><td style="text-align:center;">—</td></tr><tr><td style="text-align:left;">刻印</td><td style="text-align:left;">サブステータス付与</td><td style="text-align:center;">—</td></tr></tbody></table><h2 id="レベルアップ" tabindex="-1">レベルアップ <a class="header-anchor" href="#レベルアップ" aria-label="Permalink to &quot;レベルアップ&quot;">​</a></h2><p>経験値素材を消費して覚醒体のレベルを上げます。レベル上限はプレイヤーレベルに依存します。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>経験値素材は<a href="./../stages/resource.html">資源ステージ</a>や<a href="./../modes/dispatch.html">派遣</a>で効率的に収集できます。</p></div><h2 id="昇格-突破" tabindex="-1">昇格（突破） <a class="header-anchor" href="#昇格-突破" aria-label="Permalink to &quot;昇格（突破）&quot;">​</a></h2><p>一定レベルに達すると昇格素材を消費して突破が可能になります。突破により：</p><ul><li>レベル上限が解放される</li><li>新しい指令カードが解放される</li><li>ステータスボーナスが付与される</li></ul><h3 id="必要素材" tabindex="-1">必要素材 <a class="header-anchor" href="#必要素材" aria-label="Permalink to &quot;必要素材&quot;">​</a></h3><p><em>準備中...</em></p><h2 id="スキル強化" tabindex="-1">スキル強化 <a class="header-anchor" href="#スキル強化" aria-label="Permalink to &quot;スキル強化&quot;">​</a></h2><p>指令カード・魂覚醒カードの性能を強化します。最大Lv.6まで強化可能です。</p><p>詳細は<a href="./../cards/upgrade.html">カード強化</a>をご覧ください。</p><h2 id="啓霊-enlightenment" tabindex="-1">啓霊（Enlightenment） <a class="header-anchor" href="#啓霊-enlightenment" aria-label="Permalink to &quot;啓霊（Enlightenment）&quot;">​</a></h2><p>同一覚醒体の重複入手により啓霊レベルが上昇し、固有パッシブが解放されます。</p><p>詳細は<a href="./enlightenment.html">啓霊システム</a>をご覧ください。</p><h2 id="育成優先度" tabindex="-1">育成優先度 <a class="header-anchor" href="#育成優先度" aria-label="Permalink to &quot;育成優先度&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>JPサーバーはCNサーバーとバランス調整が異なる場合があります。最新のTier表を参考にしてください。</p></div><h3 id="序盤-lv-1〜30" tabindex="-1">序盤（Lv.1〜30） <a class="header-anchor" href="#序盤-lv-1〜30" aria-label="Permalink to &quot;序盤（Lv.1〜30）&quot;">​</a></h3><ol><li>メインアタッカー1体を集中育成</li><li>SSR覚醒体のレベルを優先</li><li>指令カードのスキルLv.3を目指す</li></ol><h3 id="中盤-lv-30〜60" tabindex="-1">中盤（Lv.30〜60） <a class="header-anchor" href="#中盤-lv-30〜60" aria-label="Permalink to &quot;中盤（Lv.30〜60）&quot;">​</a></h3><ol><li>サブアタッカー・支援型の育成開始</li><li>編成4体のレベルを均等に上げる</li><li>運命の輪の装備を開始</li></ol><h3 id="終盤-lv-60〜" tabindex="-1">終盤（Lv.60〜） <a class="header-anchor" href="#終盤-lv-60〜" aria-label="Permalink to &quot;終盤（Lv.60〜）&quot;">​</a></h3><ol><li>啓霊による凸を進める</li><li>刻印のサブステ厳選</li><li>編成全体の最適化</li></ol><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">覚醒体図鑑</a></li><li><a href="./enlightenment.html">啓霊システム</a></li><li><a href="./../cards/upgrade.html">カード強化</a></li><li><a href="./../items/materials.html">素材一覧</a></li><li><a href="./../guides/beginner.html">初心者ガイド</a></li></ul>',28)])])}const u=e(r,[["render",n]]);export{f as __pageData,u as default};
